#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $pages = $pdf->pages;

    my %metadata = (
        title => undef,
        author => undef,
        date => undef,
    );

    my @text_lines;
    for my $page (1 .. $pages) {
        my @text = $pdf->page($page)->text;
        push @text_lines, @text;
    }

    my $unidecode = Text::Unidecode->new();

    foreach my $line (@text_lines) {
        $line = $unidecode->unidecode($line);

        if ($line =~ /Title:\s*(.*)/) {
            $metadata{title} = $1;
        }
        if ($line =~ /Author:\s*(.*)/) {
            $metadata{author} = $1;
        }
        if ($line =~ /Created:\s*(.*)/) {
            $metadata{date} = $1;
        }
    }

    return %metadata;
}

sub main {
    my $pdf_file = shift;

    if (!defined $pdf_file || !-f $pdf_file) {
        die "Please provide a valid PDF file.\n";
    }

    my %metadata = extract_text($pdf_file);
    print "Title: $metadata{title}\n";
    print "Author: $metadata{author}\n";
    print "Date: $metadata{date}\n";
}

main(@ARGV);
